   121→	if sub.Type == "semantic_release" && (sub.ProjectID == nil || *sub.ProjectID == "") {
   122→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_id is required when type is 'semantic_release'")
   123→		return
